import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RoomData {
  room: string;
  pm25: number;
  co2: number;
  humidity: number;
}

interface AirQualityData {
  currentLocation: RoomData;
  roomsComparison: RoomData[];
}

export default function Widget() {
  const airQualityData = response.data as AirQualityData;
  const { currentLocation, roomsComparison } = airQualityData;
  const clipPathId = React.useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#F5F5F5' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: response.meta.primaryColor }}>
              {currentLocation.room} Air Quality
            </Typography>
            <Stack direction="row" spacing={1}>
              <Chip label={`PM2.5: ${currentLocation.pm25}`} color="primary" sx={{ fontSize: '11px', bgcolor: response.meta.accentColor, color: '#fff' }} />
              <Chip label={`CO2: ${currentLocation.co2}`} color="primary" sx={{ fontSize: '11px', bgcolor: response.meta.accentColor, color: '#fff' }} />
              <Chip label={`Humidity: ${currentLocation.humidity}%`} color="primary" sx={{ fontSize: '11px', bgcolor: response.meta.accentColor, color: '#fff' }} />
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: roomsComparison.map(room => room.pm25),
                  color: '#4CAF50',
                  label: 'PM2.5',
                },
                {
                  type: 'bar',
                  data: roomsComparison.map(room => room.co2),
                  color: '#FF5722',
                  label: 'CO2',
                },
                {
                  type: 'bar',
                  data: roomsComparison.map(room => room.humidity),
                  color: '#03A9F4',
                  label: 'Humidity',
                }
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: roomsComparison.map(room => room.room),
                  id: 'rooms',
                },
              ]}
              yAxis={[{ id: 'values' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="rooms"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="values"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
